+// Bit 0: is_ident_start (a-z, A-Z, _, $)
+// Bit 1: is_ident_char  (a-z, A-Z, 0-9, _, $)
+// Bit 2: is_quote       (", ', `)
+// Bit 3: is_brace_open  ({)
+// Bit 4: is_brace_close (})
