+static CHAR_TABLE: Lazy<[u8; 256]> = Lazy::new(|| {
+    let mut t = [0u8; 256];
+    for b in b'a'..=b'z' {
+        t[b as usize] = IDENT_START | IDENT_CHAR;
+    }
+    for b in b'A'..=b'Z' {
+        t[b as usize] = IDENT_START | IDENT_CHAR;
+    }
+    t[b'_' as usize] = IDENT_START | IDENT_CHAR;
+    t[b'$' as usize] = IDENT_START | IDENT_CHAR;
+    for b in b'0'..=b'9' {
+        t[b as usize] = IDENT_CHAR;
+    }
+    t
+});
